This is making the assumption that st_dev on windows refers to the device id.

From https://msdn.microsoft.com/en-us/library/14h5k7ff.aspx

```c
> printf( "Drive         : %c:\n", buf.st_dev + 'A' );  
Drive         : C:  
```

So it seems really just refers to a specific drive. If inodes can be the same across drives in Windows, then we can simply get the drive letter and use that as part of the key (inode, drive_letter) to refer to a specific file.

This takes ~.07 seconds to scan 60K files, where the old version using listdir()/stat() takes ~15 seconds.

```python
class DirectorySnapshotFast(DirectorySnapshot):
    def __init__(self, path, recursive=True, walker_callback=(lambda p, s: None), stat=default_stat, listdir=os.listdir):
        self.recursive = recursive
        self.walker_callback = walker_callback
        self.stat = stat
        self.listdir = listdir
        self._stat_info = {}
        self._inode_to_path = {}

        st = stat(path)
        self._stat_info[path] = st
        self._inode_to_path[(st.st_ino, st.st_dev)] = path

        for e in self.scandirs(path):
            if os.name == 'nt':
                i = (e.inode(), self._getdrive(e.path))  # USE DRIVE LETTER FOR WINDOWS
            else:
                i = (e.inode(), e.stat().st_dev)

            self._inode_to_path[i] = e.path
            self._stat_info[e.path] = e.stat()

    def _getdrive(self, path):
        drive, tail = os.path.splitdrive(path)
        return drive

    def scandirs(self, top):
        for e in os.scandir(top):
            yield e

            try:
                is_dir = e.is_dir()
            except OSError:
                is_dir = False

            if is_dir:
                yield from self.scandirs(e.path)

    def mtime(self, path):
        return self._stat_info[path].st_mtime
```

Obviously there might be a bug or an edge case in there, but would like to see this get implemented for DirectorySnapshot (and possibly other areas)

